import { state, CONFIG, saveToDB } from './state.js';
import { showToast } from './ui.js';

/**
 * 🔐 Auth & Google Drive Service Layer
 */
let tokenClient;
const syncFingerprints = new Map();
let isSyncing = false;

export async function initGoogleAuth() {
  const waitForScripts = () => new Promise((resolve, reject) => {
    let attempts = 0;
    const interval = setInterval(() => {
        attempts++;
        if (typeof gapi !== 'undefined' && typeof google !== 'undefined' && google.accounts) {
            clearInterval(interval);
            resolve();
        }
        if (attempts > 50) { // 5s timeout
            clearInterval(interval);
            reject("Google Auth scripts failed to load in time.");
        }
    }, 100);
  });

  try {
    await waitForScripts();
    
    // GAPI Client Load
    await new Promise((resolve) => gapi.load('client:picker', resolve));
    await startGapi();

    // identity Services Load
    tokenClient = google.accounts.oauth2.initTokenClient({
      client_id: CONFIG.clientId,
      scope: CONFIG.scopes,
      callback: (resp) => { 
        if (resp.access_token) {
          state.isLockerSynced = true;
          localStorage.setItem('is_locker_synced', 'true');
        }
      }
    });

    console.log("🔐 [AUTH] tokenClient initialized successfully.");
  } catch (err) {
    console.error("🔐 [AUTH] Initialization Failure:", err);
    // Don't show toast here as it might be a normal offline/blocked case
  }
}

/**
 * ☁️ [KZM-RESTORE] 클라우드 저장소에서 .kzm 패킷 일괄 복구 (v21.0)
 */
export async function loadEventsFromDrive() {
    if (!state.lockerFolderId) return;
    
    try {
        const { unpackKzm, buildSlimRecord } = await import('./kzm.js');
        const { EventDB } = await import('./db.js');

        showToast("클라우드 보관함 데이터를 확인 중입니다...", "info");

        // 1. 드라이브 내 모든 .kzm 파일 검색
        const search = await gapi.client.drive.files.list({
            q: `'${state.lockerFolderId}' in parents and trashed = false and name contains '.kzm'`,
            fields: "files(id, name, modifiedTime)"
        });

        const cloudFiles = search.result.files || [];
        if (cloudFiles.length === 0) {
            console.log("☁️ No .kzm packets found. Attempting legacy metadata fallback...");
            return await legacyRestore();
        }

        console.log(`☁️ [RESTORE] Found ${cloudFiles.length} kzm packets. Updating local cache...`);
        
        let restoredCount = 0;
        for (const file of cloudFiles) {
            // 중복 체크: 이미 IndexedDB에 이 packetDriveId가 있는지 확인
            const alreadyExists = await EventDB.hasDriveId(file.id);
            if (alreadyExists) continue;

            try {
                const blob = await fetchKzmById(file.id);
                if (blob) {
                    const ev = await unpackKzm(blob);
                    ev.packetDriveId = file.id;

                    if (!state.eventStore.some(m => String(m.id) === String(ev.id))) {
                        state.eventStore.push(ev);
                        state.existingIds.add(String(ev.id));
                        restoredCount++;
                    }

                    const slim = await buildSlimRecord(ev);
                    await EventDB.put(slim);
                }
            } catch (err) {
                console.warn(`[RESTORE-FAIL] ${file.name}:`, err);
            }
        }

        if (restoredCount > 0) {
            showToast(`${restoredCount}건의 추억을 클라우드에서 안전하게 소환했습니다.`, "success");
            refreshUI();
        } else {
            console.log("☁️ Everything is already up to date.");
        }

    } catch (err) {
        console.error("KZM Restore Error:", err);
    }
}

/**
 * 🏺 [LEGACY-FALLBACK] 옛날 방식의 메타데이터(JSON) 복구
 */
async function legacyRestore() {
    try {
        const fileName = "kuzmo_metadata.json";
        const search = await gapi.client.drive.files.list({
            q: `name = '${fileName}' and '${state.lockerFolderId}' in parents and trashed = false`,
            fields: "files(id)"
        });
        const fileId = search.result.files[0]?.id;
        if (!fileId) return console.log("☁️ No legacy metadata found either.");
        
        const response = await gapi.client.drive.files.get({ fileId, alt: 'media' });
        const cloudData = typeof response.result === 'string' ? JSON.parse(response.result) : response.result;
        
        if (Array.isArray(cloudData)) {
            let count = 0;
            for (const ev of cloudData) {
                if (!state.eventStore.some(m => String(m.id) === String(ev.id))) {
                    state.eventStore.push(ev);
                    state.existingIds.add(String(ev.id));
                    count++;
                }
            }
            if (count > 0) {
                const { saveToDB } = await import('./state.js');
                saveToDB(); 
                refreshUI();
                showToast(`레거시 데이터 ${count}건 복구 완료`, "info");
            }
        }
    } catch (err) {
        console.warn("Legacy Restore Fail:", err);
    }
}



function refreshUI() {
    import('./map.js').then(m => {
        state.eventStore.forEach(e => m.addMarkerToMap(e));
        import('./search.js').then(s => s.filterMarkers());
    });
    import('./ui.js').then(u => {
        u.renderLockerSlots();
        const badge = document.getElementById('total-count-badge');
        if (badge) badge.innerText = state.eventStore.length;
    });
}


async function startGapi() {
  if (!gapi.client) return;
  try {
    await gapi.client.init({
      apiKey: CONFIG.apiKey,
      discoveryDocs: CONFIG.discoveryDocs,
    });
    // 🚀 Explicitly set API Key for Picker and other services
    gapi.client.setApiKey(CONFIG.apiKey);
    console.log("✅ GAPI Client Initialized & API Key Set");
  } catch (err) {
    const errorMsg = err?.result?.error?.message || err?.details || JSON.stringify(err);
    console.error("❌ GAPI Init Failure Details:", errorMsg);
    
    if (errorMsg.includes("origin") || errorMsg.includes("Referer")) {
        console.warn("💡 원인: GCP 콘솔의 API 키 '웹사이트 제한사항'에 http://localhost:9005/* 를 추가해야 합니다.");
    } else if (errorMsg.includes("disallowed")) {
        console.warn("💡 원인: GCP 콘솔에서 해당 API 키에 'Google Drive API' 사용 권한이 체크되어 있는지 확인하세요.");
    }
  }
}
window.startGapiManual = startGapi; // Debugging fallback


export function handleAuthClick() {
  console.log("🔥 [AUTH] handleAuthClick fired!");
  if (!tokenClient) {
      showToast("Google Auth 시스템이 아직 준비되지 않았습니다.", "error");
      return;
  }
    tokenClient.callback = async (resp) => {
      if (resp.error !== undefined) throw (resp);
      state.isLockerSynced = true;
      localStorage.setItem('is_locker_synced', 'true');
      showToast("Google Drive 연동 성공", "success");
      
      // 🚀 로그인 직후 전체 데이터 복구 시도
      await loadEventsFromDrive();
      
      const unsynced = document.getElementById('locker-unsynced');
    const folderPicker = document.getElementById('locker-folder-picker');
    if (unsynced) unsynced.style.display = 'none';
    if (folderPicker) {
      folderPicker.style.display = 'flex';
      // 실제 시나리오에서는 여기서 API를 호출하여 폴더 목록을 가져옴
      // workflow 지침에 따라 실제 로직처럼 동작하도록 하드코딩 탈피 시도
      const { refreshFolderList } = await import('./ui.js');
      refreshFolderList();
    }
  };

  if (!gapi.client || gapi.client.getToken() === null) {
    tokenClient.requestAccessToken({ prompt: 'consent' });
  } else {
    tokenClient.requestAccessToken({ prompt: '' });
  }
}

// 🚀 [Kuzmo_Archive] 전용 폴더 자동 생성 및 연동
export async function createArchiveFolderAuto() {
  try {
    const folderName = "Kuzmo_Archive";
    
    // 1. 이미 존재하는지 확인
    const search = await gapi.client.drive.files.list({
      q: `name = '${folderName}' and mimeType = 'application/vnd.google-apps.folder' and trashed = false`,
      fields: "files(id, name)"
    });

    let folderId;
    if (search.result.files.length > 0) {
      folderId = search.result.files[0].id;
      showToast(`기존 '${folderName}' 폴더를 발견하여 연동합니다.`, "info");
    } else {
      // 2. 없으면 생성
      const resp = await gapi.client.drive.files.create({
        resource: {
          name: folderName,
          mimeType: 'application/vnd.google-apps.folder'
        },
        fields: 'id'
      });
      folderId = resp.result.id;
      showToast(`새로운 '${folderName}' 폴더를 생성했습니다.`, "success");
    }

    // 3. 연동
    const { selectLockerFolder } = await import('./ui.js');
    selectLockerFolder(folderName, folderId);
    
    // 4. 즉시 파일 업로드 시도 (백업)
    await syncEventsToDrive();
  } catch (err) {
    console.error("Auto Folder Creation Error:", err);
    showToast("폴더 자동 생성 중 오류가 발생했습니다.", "error");
  }
}

// 📂 로그인 후 다음 로직: 폴더 리스트 연동 및 선택
export async function fetchDriveFolders() {
  try {
    if (!gapi?.client?.drive) {
        console.warn("⚠️ GAPI Drive client not ready yet.");
        return [];
    }
    const response = await gapi.client.drive.files.list({
      q: "mimeType = 'application/vnd.google-apps.folder' and trashed = false",
      fields: "files(id, name)",
      pageSize: 10
    });
    return response.result.files || [];
  } catch (err) {
    console.error("Folder fetch error:", err);
    return [];
  }
}

// 📂 폴더 내 파일 목록 조회 (보관함 실제 데이터)
export async function fetchFilesInFolder(folderId) {
  if (!folderId) return [];
  try {
    if (!gapi?.client?.drive) {
        console.warn("⚠️ GAPI Drive client not ready for files.");
        return [];
    }
    const response = await gapi.client.drive.files.list({
      q: `'${folderId}' in parents and trashed = false`,
      fields: "files(id, name, thumbnailLink, mimeType, webViewLink)",
      pageSize: 20
    });
    return response.result.files || [];
  } catch (err) {
    console.error("File fetch error:", err);
    return [];
  }
}

// 🎯 [NEW] Google Picker API: 공식 문서 권장 폴더 선택기
export function showPicker() {
  const token = gapi.client.getToken();
  if (!token) {
    handleAuthClick(); 
    return;
  }

  // Debugging: Verify config before building picker
  console.log("📂 Launching Google Picker with:", {
    appId: CONFIG.appId,
    hasToken: !!token.access_token,
    keyExists: !!CONFIG.apiKey,
    keyPrefix: CONFIG.apiKey ? CONFIG.apiKey.substring(0, 8) : 'NONE'
  });

  const view = new google.picker.DocsView(google.picker.ViewId.FOLDERS)
    .setSelectFolderEnabled(true)
    .setIncludeFolders(true)
    .setMimeTypes('application/vnd.google-apps.folder');

  const picker = new google.picker.PickerBuilder()
    .addView(view)
    .setOAuthToken(token.access_token)
    .setDeveloperKey(CONFIG.apiKey)
    .setAppId(CONFIG.appId) 
    .setOrigin(window.location.origin) // 🚀 필수: 9005번 포트와 같은 커스텀 origin 명시
    .setCallback(pickerCallback)
    .build();
  
  picker.setVisible(true);
}

async function pickerCallback(data) {
  if (data.action === google.picker.Action.PICKED) {
    const doc = data.docs[0];
    const name = doc.name;
    const id = doc.id;
    
    // UI 모듈의 글로벌 함수 호출
    const { selectLockerFolder } = await import('./ui.js');
    selectLockerFolder(name, id);
  }
}
/**
 * ☁️ [KZM SYNC] .kzm 패킷 단위 동기화 (v20.0)
 * 이벤트 1개 = Drive 1개 .kzm 파일
 */
export async function syncEventsToDrive() {
    if (!state.lockerFolderId || isSyncing) return;
    isSyncing = true;

    try {
        const { packKzm, buildSlimRecord } = await import('./kzm.js');
        const { EventDB } = await import('./db.js');

        console.log("☁️ [KZM-SYNC] Starting .kzm packet sync...");

        // 1. 기존 .kzm 파일 목록 (중복 업로드 방지)
        const listResp = await gapi.client.drive.files.list({
            q: `'${state.lockerFolderId}' in parents and trashed = false and name contains '.kzm'`,
            fields: "files(id, name)"
        });
        const driveKzmMap = new Map(listResp.result.files.map(f => [f.name, f.id]));

        let syncCount = 0;

        for (const ev of state.eventStore) {
            const kzmName = `${ev.title.replace(/[\\/:*?"<>|]/g, '_')}_${String(ev.id).substring(0, 8)}.kzm`;
            const fingerprint = (ev.timestamp || 0) + '_' + (ev.tags?.length || 0) + '_' + (ev.imageUrl || '').length;

            if (syncFingerprints.get(ev.id) === fingerprint) continue;

            try {
                // 2. .kzm 패킹
                const kzmBlob = await packKzm(ev);
                const existingId = driveKzmMap.get(kzmName);

                // 3. Drive 업로드 (upsert)
                const fileId = await uploadDriveFile(kzmName, kzmBlob, state.lockerFolderId, 'application/x-kzm', existingId);

                if (fileId) {
                    syncFingerprints.set(ev.id, fingerprint);
                    syncCount++;

                    // 4. 슬림 캐시에 packetDriveId 기록
                    const slim = await buildSlimRecord({ ...ev, packetDriveId: fileId });
                    await EventDB.put(slim);
                }
            } catch (packErr) {
                console.warn(`[KZM] Pack/Upload failed for ${ev.title}:`, packErr);
            }

            if (syncCount % 3 === 0) await new Promise(r => setTimeout(r, 80));
        }

        if (syncCount > 0) {
            console.log(`✅ [KZM-SYNC] ${syncCount} .kzm packets uploaded.`);
            showToast(`${syncCount}건의 추억이 .kzm으로 클라우드에 백업됨`, "success");
        } else {
            console.log("✅ [KZM-SYNC] All up to date.");
        }

    } catch (err) {
        console.error("KZM Sync Error:", err);
    } finally {
        isSyncing = false;
    }
}

