/**
 * 💾 [DATA-SYNC] 바이너리/텍스트 범용 파일 업로드 (이미지, 오디오, JSON)
 */
export async function uploadDriveFile(name, blob, parentId, mimeType = 'application/json', existingId = null) {
    try {
        let fileId = existingId;
        
        // 1. 중복 조회 (이미 존재하면 업데이트)
        if (!fileId) {
            const search = await gapi.client.drive.files.list({
                q: `name = '${name}' and '${parentId}' in parents and trashed = false`,
                fields: "files(id)"
            });
            fileId = search.result.files[0]?.id;
        }

        const url = fileId 
            ? `https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=multipart`
            : `https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart`;
        
        const metadata = { name, parents: [parentId], mimeType };
        const form = new FormData();
        form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
        form.append('file', blob);

        const resp = await fetch(url, {
            method: fileId ? 'PATCH' : 'POST',
            headers: { 'Authorization': `Bearer ${gapi.client.getToken().access_token}` },
            body: form
        });
        const result = await resp.json();
        return result.id;

    } catch (err) {
        console.error(`Upload error [${name}]:`, err);
        return null;
    }
}



/**
 * 🕵️ [KZM-AUDIT] 로컬 vs 클라우드 .kzm 패킷 1:1 정밀 비교 검사 (v21.0)
 */
export async function deepSyncAudit() {
  if (!state.isLockerSynced || !state.lockerFolderId) {
    return showToast("구글 드라이브 연동이 필요합니다.", "info");
  }

  showToast("클라우드 .kzm 보관함 정밀 대조 시작...", "info");
  
  try {
    // 1. 드라이브 내 모든 .kzm 파일 목록 확보
    const search = await gapi.client.drive.files.list({
        q: `'${state.lockerFolderId}' in parents and trashed = false and name contains '.kzm'`,
        fields: "files(id, name, modifiedTime)"
    });
    const cloudFiles = search.result.files || [];
    
    // 2. 대조를 위한 Map 생성
    const cloudNameMap = new Map(cloudFiles.map(f => [f.name, f.id]));
    const localMap = new Map(state.eventStore.map(e => [e.id, e]));

    const missingInCloud = [];
    const missingInLocal = [];
    const mismatches = [];

    // 로컬 → 클라우드 체크
    for (const ev of state.eventStore) {
        const kzmName = `${ev.id}_${ev.title.replace(/[/\\?%*:|"<>]/g, '_')}.kzm`;
        if (!cloudNameMap.has(kzmName)) {
            missingInCloud.push({ id: ev.id, title: ev.title });
        }
    }

    // 클라우드 → 로컬 체크
    for (const file of cloudFiles) {
        const idFromCloud = file.name.split('_')[0];
        if (!localMap.has(idFromCloud)) {
            missingInLocal.push({ id: idFromCloud, name: file.name });
        }
    }

    const status = (missingInCloud.length === 0 && missingInLocal.length === 0) ? "PERFECT_MATCH" : "DISCREPANCY_FOUND";

    console.group("📑 [KZM-AUDIT REPORT v21.0]");
    console.table({
      "Local Total": state.eventStore.length,
      "Cloud Total": cloudFiles.length,
      "Missing in Cloud": missingInCloud.length,
      "Missing in Local": missingInLocal.length,
      "Status": status
    });
    console.groupEnd();

    if (status === "PERFECT_MATCH") {
      showToast("✅ 클라우드와 1:1 완벽하게 일치합니다!", "success");
    } else {
      showToast(`검사 완료: 불일치 발견 (로컬 전용 ${missingInCloud.length}건, 클라우드 전용 ${missingInLocal.length}건)`, "warning");
    }

    return { success: true, status, missingInCloud, missingInLocal };

  } catch (err) {
    console.error("KZM Audit Failure:", err);
    showToast("정밀 검사 중 오류가 발생했습니다.", "error");
    return { success: false, error: err };
  }
}

