/**
 * 📦 [KZM-HYDRATION] Drive에서 .kzm 패킷을 Blob으로 다운로드
 */
export async function fetchKzmById(fileId) {
    if (!fileId) return null;
    try {
        const response = await gapi.client.drive.files.get({
            fileId: fileId,
            alt: 'media'
        });

        const content = typeof response.body === 'string' ? response.body : JSON.stringify(response.result);
        return new Blob([content], { type: 'application/x-kzm' });
    } catch (err) {
        console.error("KZM Download Fail:", err);
        return null;
    }
}
